def gen(rng, size):
    import string
    def rword(maxlen):
        L = rng.randint(1, maxlen)
        chars = []
        for _ in range(L):
            c = rng.choice(string.ascii_letters)
            chars.append(c)
        return ''.join(chars)
    nq = max(1, min(size, 100))
    queries = [rword(12) for _ in range(nq)]
    pattern = rword(5)
    return [queries, pattern]

