class Solution:
    def camelMatch(self, queries, pattern):
        # Brute force: split each word into (lowercase-runs, uppercase markers)
        # and compare the uppercase skeletons plus subsequence-of lowercase.
        def matches(q, p):
            i = 0
            for ch in q:
                if i < len(p) and ch == p[i]:
                    i += 1
                elif ch.isupper():
                    return False
            return i == len(p)
        return [matches(q, pattern) for q in queries]

