var camelMatch = function(queries, pattern) {
    const isUpper = (c) => c >= 'A' && c <= 'Z';
    function ok(q) {
        let i = 0;
        for (const ch of q) {
            if (i < pattern.length && ch === pattern[i]) {
                i += 1;
            } else if (isUpper(ch)) {
                return false;
            }
        }
        return i === pattern.length;
    }
    return queries.map(ok);
};
